                                let caller_idx = self.frames.len().saturating_sub(1);
                                let result = self.call_builtin(builtin, args, kwargs)?;
                                let frame = self.frames.get_mut(caller_idx).ok_or_else(|| {
                                    RuntimeError::new("builtin caller frame missing")
                                })?;
