    fn builtin_min(
        &mut self,
        args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        self.builtin_min_max(args, kwargs, Ordering::Less, "min")
    }

    fn builtin_max(
        &mut self,
        args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        self.builtin_min_max(args, kwargs, Ordering::Greater, "max")
    }

    fn builtin_min_max(
        &mut self,
        mut args: Vec<Value>,
        mut kwargs: HashMap<String, Value>,
        preferred: Ordering,
        name: &str,
    ) -> Result<Value, RuntimeError> {
        let default = kwargs.remove("default");
        let key_func = kwargs.remove("key").unwrap_or(Value::None);
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(&format!(
                "{name}() got an unexpected keyword argument"
            )));
        }
        if args.is_empty() {
            return Err(RuntimeError::new(&format!(
                "{name}() expected at least 1 argument, got 0"
            )));
        }

        let values = if args.len() == 1 {
            self.collect_iterable_values(args.remove(0))?
        } else {
            if default.is_some() {
                return Err(RuntimeError::new(&format!(
                    "Cannot specify a default for {name}() with multiple positional arguments"
                )));
            }
            args
        };

        if values.is_empty() {
            if let Some(default_value) = default {
                return Ok(default_value);
            }
            return Err(RuntimeError::new(&format!(
                "{name}() arg is an empty sequence"
            )));
        }

        let mut iter = values.into_iter();
        let mut best_value = iter.next().expect("values is non-empty");
        let mut best_key = if matches!(key_func, Value::None) {
            best_value.clone()
        } else {
            match self.call_internal(key_func.clone(), vec![best_value.clone()], HashMap::new())? {
                InternalCallOutcome::Value(key) => key,
                InternalCallOutcome::CallerExceptionHandled => {
                    return Err(RuntimeError::new("key function raised"));
                }
            }
        };

        for value in iter {
            let key = if matches!(key_func, Value::None) {
                value.clone()
            } else {
                match self.call_internal(key_func.clone(), vec![value.clone()], HashMap::new())? {
                    InternalCallOutcome::Value(key) => key,
                    InternalCallOutcome::CallerExceptionHandled => {
                        return Err(RuntimeError::new("key function raised"));
                    }
                }
            };
            if self.compare_sort_keys(key.clone(), best_key.clone())? == preferred {
                best_value = value;
                best_key = key;
            }
        }

        Ok(best_value)
    }

    fn builtin_sorted(
        &mut self,
        mut args: Vec<Value>,
        mut kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if args.len() != 1 {
            return Err(RuntimeError::new("sorted() expects one iterable argument"));
        }
        let reverse = kwargs
            .remove("reverse")
            .map(|value| is_truthy(&value))
            .unwrap_or(false);
        let key_func = kwargs.remove("key").unwrap_or(Value::None);
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(
                "sorted() got an unexpected keyword argument",
            ));
        }

        let mut values = self.collect_iterable_values(args.remove(0))?;
        if !matches!(key_func, Value::None) {
            let mut keyed = Vec::with_capacity(values.len());
            for value in values {
                let key = match self.call_internal(
                    key_func.clone(),
                    vec![value.clone()],
                    HashMap::new(),
                )? {
                    InternalCallOutcome::Value(key) => key,
                    InternalCallOutcome::CallerExceptionHandled => {
                        return Err(RuntimeError::new("key function raised"));
                    }
                };
                keyed.push((value, key));
            }
            let mut compare_error: Option<RuntimeError> = None;
            keyed.sort_by(|left, right| {
                match self.compare_sort_keys(left.1.clone(), right.1.clone()) {
                    Ok(ordering) => ordering,
                    Err(err) => {
                        compare_error = Some(err);
                        Ordering::Equal
                    }
                }
            });
            if let Some(err) = compare_error {
                return Err(err);
            }
            if reverse {
                keyed.reverse();
            }
            values = keyed.into_iter().map(|(value, _)| value).collect();
        } else {
            let mut compare_error: Option<RuntimeError> = None;
            values.sort_by(
                |left, right| match compare_order(left.clone(), right.clone()) {
                    Ok(ordering) => ordering,
                    Err(err) => {
                        compare_error = Some(err);
                        Ordering::Equal
                    }
                },
            );
            if let Some(err) = compare_error {
                return Err(err);
            }
            if reverse {
                values.reverse();
            }
        }
        Ok(self.heap.alloc_list(values))
    }

    fn compare_sort_keys(&mut self, left: Value, right: Value) -> Result<Ordering, RuntimeError> {
        if let Some(ordering) = self.compare_cmp_to_key_wrappers(&left, &right)? {
            return Ok(ordering);
        }
        compare_order(left, right)
    }

    fn compare_cmp_to_key_wrappers(
        &mut self,
        left: &Value,
        right: &Value,
    ) -> Result<Option<Ordering>, RuntimeError> {
        let Some((comparator, left_obj)) = self.cmp_to_key_wrapper_parts(left) else {
            return Ok(None);
        };
        let Some((_, right_obj)) = self.cmp_to_key_wrapper_parts(right) else {
            return Ok(None);
        };
        let result =
            match self.call_internal(comparator, vec![left_obj, right_obj], HashMap::new())? {
                InternalCallOutcome::Value(value) => value,
                InternalCallOutcome::CallerExceptionHandled => {
                    return Err(RuntimeError::new("cmp_to_key comparator raised"));
                }
            };
        Ok(Some(ordering_from_cmp_value(result)?))
    }

    fn cmp_to_key_wrapper_parts(&self, value: &Value) -> Option<(Value, Value)> {
        let Value::Module(module) = value else {
            return None;
        };
        match &*module.kind() {
            Object::Module(module_data) if module_data.name == "__functools_cmp_key_item__" => {
                let comparator = module_data.globals.get("cmp")?.clone();
                let object = module_data.globals.get("obj")?.clone();
                Some((comparator, object))
            }
            _ => None,
        }
    }

    fn builtin_all(
        &mut self,
        args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        self.builtin_all_any(args, kwargs, true)
    }

    fn builtin_any(
        &mut self,
        args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        self.builtin_all_any(args, kwargs, false)
    }

    fn builtin_all_any(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
        expect_all: bool,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() || args.len() != 1 {
            return Err(RuntimeError::new("all/any expects one argument"));
        }
        let iterable = args.remove(0);
        let iter = self
            .to_iterator_value(iterable)
            .map_err(|_| RuntimeError::new("all/any expects iterable"))?;

        let mut result = expect_all;
        match iter {
            Value::Iterator(iterator_ref) => {
                while let Some(value) = self.iterator_next_value(&iterator_ref) {
                    let truthy = is_truthy(&value);
                    if expect_all {
                        if !truthy {
                            result = false;
                            break;
                        }
                    } else if truthy {
                        result = true;
                        break;
                    }
                }
            }
            Value::Generator(generator) => loop {
                match self.generator_for_iter_next(&generator)? {
                    GeneratorResumeOutcome::Yield(value) => {
                        let truthy = is_truthy(&value);
                        if expect_all {
                            if !truthy {
                                result = false;
                                break;
                            }
                        } else if truthy {
                            result = true;
                            break;
                        }
                    }
                    GeneratorResumeOutcome::Complete(_) => break,
                    GeneratorResumeOutcome::PropagatedException => {
                        self.propagate_pending_generator_exception()?;
                        return Err(RuntimeError::new("iteration failed"));
                    }
                }
            },
            _ => return Err(RuntimeError::new("all/any expects iterable")),
        }
        Ok(Value::Bool(result))
    }

    fn builtin_reversed(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() || args.len() != 1 {
            return Err(RuntimeError::new("reversed() expects one argument"));
        }
        let source = args.remove(0);
        let mut values = self.collect_iterable_values(source)?;
        values.reverse();
        Ok(self.heap.alloc_list(values))
    }

    fn builtin_zip(
        &mut self,
        args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() {
            return Err(RuntimeError::new("zip() does not accept keyword arguments"));
        }
        if args.is_empty() {
            return Ok(self.heap.alloc_list(Vec::new()));
        }
        let mut columns = Vec::with_capacity(args.len());
        for source in args {
            columns.push(self.collect_iterable_values(source)?);
        }
        let len = columns.iter().map(Vec::len).min().unwrap_or(0);
        let mut rows = Vec::with_capacity(len);
        for idx in 0..len {
            let mut tuple_items = Vec::with_capacity(columns.len());
            for col in &columns {
                tuple_items.push(col[idx].clone());
            }
            rows.push(self.heap.alloc_tuple(tuple_items));
        }
        Ok(self.heap.alloc_list(rows))
    }

    fn is_callable_value(&self, value: &Value) -> bool {
        match value {
            Value::Function(_) | Value::Builtin(_) | Value::BoundMethod(_) | Value::Class(_) => {
                true
            }
            Value::Instance(instance) => match &*instance.kind() {
                Object::Instance(instance_data) => {
                    class_attr_lookup(&instance_data.class, "__call__").is_some()
                }
                _ => false,
            },
            _ => false,
        }
    }

    fn value_is_instance_of(&self, value: &Value, classinfo: &Value) -> Result<bool, RuntimeError> {
        match classinfo {
            Value::Tuple(obj) => match &*obj.kind() {
                Object::Tuple(items) => {
                    for item in items {
                        if self.value_is_instance_of(value, item)? {
                            return Ok(true);
                        }
                    }
                    Ok(false)
                }
                _ => Err(RuntimeError::new(
                    "isinstance() arg 2 must be a type or tuple of types",
                )),
            },
            Value::List(obj) => match &*obj.kind() {
                Object::List(items) => {
                    for item in items {
                        if self.value_is_instance_of(value, item)? {
                            return Ok(true);
                        }
                    }
                    Ok(false)
                }
                _ => Err(RuntimeError::new(
                    "isinstance() arg 2 must be a type or tuple of types",
                )),
            },
            Value::Class(expected) => match value {
                _ => {
                    if let Object::Class(class_data) = &*expected.kind() {
                        let marker_match = match class_data.name.as_str() {
                            "NoneType" => matches!(value, Value::None),
                            "function" => matches!(value, Value::Function(_)),
                            "method" => matches!(value, Value::BoundMethod(_)),
                            "builtin_function_or_method" => matches!(value, Value::Builtin(_)),
                            "code" => matches!(value, Value::Code(_)),
                            _ => false,
                        };
                        if marker_match {
                            return Ok(true);
                        }
                    }
                    match value {
                        Value::Instance(instance) => match &*instance.kind() {
                            Object::Instance(instance_data) => Ok(self
                                .class_mro_entries(&instance_data.class)
                                .iter()
                                .any(|entry| entry.id() == expected.id())),
                            _ => Ok(false),
                        },
                        Value::Class(class) => {
                            let Some(meta_class) = class_of_class(class) else {
                                return Ok(false);
                            };
                            Ok(self
                                .class_mro_entries(&meta_class)
                                .iter()
                                .any(|entry| entry.id() == expected.id()))
                        }
                        _ => Ok(false),
                    }
                }
            },
            Value::Builtin(builtin) => Ok(self.matches_builtin_type_marker(value, *builtin)),
            Value::ExceptionType(name) => match value {
                Value::Exception(exception) => {
                    Ok(exception_type_is_subclass(&exception.name, name))
                }
                Value::ExceptionType(candidate) => Ok(exception_type_is_subclass(candidate, name)),
                _ => Ok(false),
            },
            _ => Err(RuntimeError::new(
                "isinstance() arg 2 must be a type or tuple of types",
            )),
        }
    }

    fn class_value_is_subclass_of(
        &self,
        candidate: &Value,
        classinfo: &Value,
    ) -> Result<bool, RuntimeError> {
        match classinfo {
            Value::Tuple(obj) => match &*obj.kind() {
                Object::Tuple(items) => {
                    for item in items {
                        if self.class_value_is_subclass_of(candidate, item)? {
                            return Ok(true);
                        }
                    }
                    Ok(false)
                }
                _ => Err(RuntimeError::new(
                    "issubclass() arg 2 must be a type or tuple of types",
                )),
            },
            Value::List(obj) => match &*obj.kind() {
                Object::List(items) => {
                    for item in items {
                        if self.class_value_is_subclass_of(candidate, item)? {
                            return Ok(true);
                        }
                    }
                    Ok(false)
                }
                _ => Err(RuntimeError::new(
                    "issubclass() arg 2 must be a type or tuple of types",
                )),
            },
            Value::Class(expected) => match candidate {
                Value::Class(class) => Ok(self
                    .class_mro_entries(class)
                    .iter()
                    .any(|entry| entry.id() == expected.id())),
                Value::Builtin(_) => {
                    let Object::Class(class_data) = &*expected.kind() else {
                        return Ok(false);
                    };
                    Ok(class_data.name == "object")
                }
                _ => Err(RuntimeError::new("issubclass() arg 1 must be a class")),
            },
            Value::Builtin(expected_builtin) => match candidate {
                Value::Builtin(candidate_builtin) => Ok(candidate_builtin == expected_builtin),
                Value::Class(_) => Ok(matches!(expected_builtin, BuiltinFunction::Type)),
                Value::ExceptionType(_) => Ok(matches!(expected_builtin, BuiltinFunction::Type)),
                _ => Err(RuntimeError::new("issubclass() arg 1 must be a class")),
            },
            Value::ExceptionType(expected_name) => match candidate {
                Value::ExceptionType(candidate_name) => {
                    Ok(exception_type_is_subclass(candidate_name, expected_name))
                }
                _ => Err(RuntimeError::new("issubclass() arg 1 must be a class")),
            },
            _ => Err(RuntimeError::new(
                "issubclass() arg 2 must be a type or tuple of types",
            )),
        }
    }

    fn matches_builtin_type_marker(&self, value: &Value, builtin: BuiltinFunction) -> bool {
        match builtin {
            BuiltinFunction::Type => {
                matches!(
                    value,
                    Value::Class(_) | Value::ExceptionType(_) | Value::Builtin(_)
                )
            }
            BuiltinFunction::Bool => matches!(value, Value::Bool(_)),
            BuiltinFunction::Int => matches!(value, Value::Int(_) | Value::Bool(_)),
            BuiltinFunction::Float => matches!(value, Value::Float(_)),
            BuiltinFunction::Str => matches!(value, Value::Str(_)),
            BuiltinFunction::List => matches!(value, Value::List(_)),
            BuiltinFunction::Tuple => matches!(value, Value::Tuple(_)),
            BuiltinFunction::Dict => matches!(value, Value::Dict(_)),
            BuiltinFunction::Set => matches!(value, Value::Set(_)),
            BuiltinFunction::FrozenSet => matches!(value, Value::FrozenSet(_)),
            BuiltinFunction::Bytes => matches!(value, Value::Bytes(_)),
            BuiltinFunction::ByteArray => matches!(value, Value::ByteArray(_)),
            BuiltinFunction::MemoryView => matches!(value, Value::MemoryView(_)),
            BuiltinFunction::Complex => matches!(value, Value::Complex { .. }),
            _ => false,
        }
    }

    fn builtin_iter(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() || args.len() != 1 {
            return Err(RuntimeError::new("iter() expects one argument"));
        }
        let source = args.remove(0);
        self.ensure_sync_iterator_target(&source)?;
        self.to_iterator_value(source)
            .map_err(|_| RuntimeError::new("object is not iterable"))
    }

    fn builtin_next(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() || args.is_empty() || args.len() > 2 {
            return Err(RuntimeError::new("next() expects 1-2 arguments"));
        }
        let default = if args.len() == 2 {
            Some(args.pop().expect("checked len"))
        } else {
            None
        };
        let target = args.pop().expect("checked len");
        self.ensure_sync_iterator_target(&target)?;
        let iterator = self
            .to_iterator_value(target)
            .map_err(|_| RuntimeError::new("next() argument is not iterable"))?;
        match iterator {
            Value::Generator(obj) => match self.generator_for_iter_next(&obj)? {
                GeneratorResumeOutcome::Yield(value) => Ok(value),
                GeneratorResumeOutcome::Complete(_) => {
                    if let Some(default) = default {
                        Ok(default)
                    } else {
                        Err(RuntimeError::new("StopIteration"))
                    }
                }
                GeneratorResumeOutcome::PropagatedException => {
                    self.propagate_pending_generator_exception()?;
                    Err(RuntimeError::new("StopIteration"))
                }
            },
            Value::Iterator(iterator_ref) => {
                if let Some(value) = self.iterator_next_value(&iterator_ref) {
                    Ok(value)
                } else if let Some(default) = default {
                    Ok(default)
                } else {
                    Err(RuntimeError::new("StopIteration"))
                }
            }
            _ => Err(RuntimeError::new("next() argument is not iterable")),
        }
    }

    fn builtin_map(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() || args.len() < 2 {
            return Err(RuntimeError::new("map() expects at least two arguments"));
        }
        let func = args.remove(0);
        let mut iterators = Vec::new();
        for source in args {
            self.ensure_sync_iterator_target(&source)?;
            let iterator = self
                .to_iterator_value(source)
                .map_err(|_| RuntimeError::new("map() argument is not iterable"))?;
            iterators.push(iterator);
        }

        let mut mapped = Vec::new();
        loop {
            let mut call_args = Vec::with_capacity(iterators.len());
            for iterator in &iterators {
                match self.next_from_iterator_value(iterator)? {
                    GeneratorResumeOutcome::Yield(value) => call_args.push(value),
                    GeneratorResumeOutcome::Complete(_) => {
                        return Ok(self.heap.alloc_list(mapped));
                    }
                    GeneratorResumeOutcome::PropagatedException => {
                        return Err(RuntimeError::new("map() iteration failed"));
                    }
                }
            }

            let value = match self.call_internal(func.clone(), call_args, HashMap::new())? {
                InternalCallOutcome::Value(value) => value,
                InternalCallOutcome::CallerExceptionHandled => {
                    return Err(RuntimeError::new("map() callable failed"));
                }
            };
            mapped.push(value);
        }
    }

    fn builtin_aiter(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() || args.len() != 1 {
            return Err(RuntimeError::new("aiter() expects one argument"));
        }
        let source = args.remove(0);
        let source_is_async_generator = if let Value::Generator(generator) = &source {
            matches!(&*generator.kind(), Object::Generator(state) if state.is_async_generator)
        } else {
            false
        };
        if source_is_async_generator {
            return Ok(source);
        }
        let method = self
            .lookup_bound_special_method(&source, "__aiter__")?
            .ok_or_else(|| RuntimeError::new("object is not async iterable"))?;
        match self.call_internal(method, Vec::new(), HashMap::new())? {
            InternalCallOutcome::Value(value) => Ok(value),
            InternalCallOutcome::CallerExceptionHandled => Err(RuntimeError::new("aiter() failed")),
        }
    }

    fn builtin_anext(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() || args.is_empty() || args.len() > 2 {
            return Err(RuntimeError::new("anext() expects 1-2 arguments"));
        }
        let default = if args.len() == 2 {
            Some(args.pop().expect("checked len"))
        } else {
            None
        };
        let target = args.pop().expect("checked len");

        let target_is_async_generator = if let Value::Generator(generator) = &target {
            matches!(&*generator.kind(), Object::Generator(state) if state.is_async_generator)
        } else {
            false
        };

        if target_is_async_generator {
            let generator = match &target {
                Value::Generator(generator) => generator,
                _ => unreachable!(),
            };
            return match self.resume_generator(generator, None, None, GeneratorResumeKind::Next)? {
                GeneratorResumeOutcome::Yield(value) => Ok(self.make_immediate_coroutine(value)),
                GeneratorResumeOutcome::Complete(_) => {
                    if let Some(default) = default {
                        Ok(self.make_immediate_coroutine(default))
                    } else {
                        Err(RuntimeError::new("StopAsyncIteration"))
                    }
                }
                GeneratorResumeOutcome::PropagatedException => {
                    self.propagate_pending_generator_exception()?;
                    Err(RuntimeError::new("StopAsyncIteration"))
                }
            };
        }

        let method = self
            .lookup_bound_special_method(&target, "__anext__")?
            .ok_or_else(|| RuntimeError::new("object is not an async iterator"))?;
        match self.call_internal(method, Vec::new(), HashMap::new())? {
            InternalCallOutcome::Value(value) => Ok(value),
            InternalCallOutcome::CallerExceptionHandled => {
                if default.is_some() && self.active_exception_is("StopAsyncIteration") {
                    self.clear_active_exception();
                    Ok(self.make_immediate_coroutine(default.expect("checked is_some")))
                } else {
                    Err(RuntimeError::new("anext() failed"))
                }
            }
        }
    }

    fn builtin_getattr(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(
                "getattr() got an unexpected keyword argument",
            ));
        }
        if args.len() < 2 || args.len() > 3 {
            return Err(RuntimeError::new("getattr() expects 2-3 arguments"));
        }

        let target = args.remove(0);
        let name = match args.remove(0) {
            Value::Str(name) => name,
            _ => return Err(RuntimeError::new("attribute name must be string")),
        };
        let default = args.into_iter().next();

        let looked_up = match target {
            Value::Module(module) => self.load_attr_module(&module, &name),
            Value::Class(class) => match self.load_attr_class(&class, &name)? {
                AttrAccessOutcome::Value(value) => Ok(value),
                AttrAccessOutcome::ExceptionHandled => Ok(Value::None),
            },
            Value::Instance(instance) => match self.load_attr_instance(&instance, &name)? {
                AttrAccessOutcome::Value(value) => Ok(value),
                AttrAccessOutcome::ExceptionHandled => Ok(Value::None),
            },
            Value::Super(super_obj) => match self.load_attr_super(&super_obj, &name)? {
                AttrAccessOutcome::Value(value) => Ok(value),
                AttrAccessOutcome::ExceptionHandled => Ok(Value::None),
            },
            Value::List(list) => self.load_attr_list_method(list, &name),
            Value::Str(text) => self.load_attr_str_method(text, &name),
            Value::Set(set) => self.load_attr_set_method(set, &name),
            Value::FrozenSet(set) => self.load_attr_set_method(set, &name),
            Value::Dict(dict) => self.load_attr_dict_method(dict, &name),
            Value::Builtin(builtin) => self.load_attr_builtin(builtin, &name),
            Value::Function(func) => self.load_attr_function(&func, &name),
            Value::Code(code) => self.load_attr_code(&code, &name),
            Value::Generator(generator) => {
                let kind = match &*generator.kind() {
                    Object::Generator(state) if state.is_async_generator => match name.as_str() {
                        "__aiter__" => NativeMethodKind::GeneratorIter,
                        "__anext__" => NativeMethodKind::GeneratorANext,
                        "asend" => NativeMethodKind::GeneratorANext,
                        "athrow" => NativeMethodKind::GeneratorThrow,
                        "aclose" => NativeMethodKind::GeneratorClose,
                        "throw" => NativeMethodKind::GeneratorThrow,
                        "close" => NativeMethodKind::GeneratorClose,
                        _ => {
                            return Err(RuntimeError::new(format!(
                                "async_generator has no attribute '{}'",
                                name
                            )));
                        }
                    },
                    Object::Generator(state) if state.is_coroutine => match name.as_str() {
                        "__await__" => NativeMethodKind::GeneratorAwait,
                        "send" => NativeMethodKind::GeneratorSend,
                        "throw" => NativeMethodKind::GeneratorThrow,
                        "close" => NativeMethodKind::GeneratorClose,
                        _ => {
                            return Err(RuntimeError::new(format!(
                                "coroutine has no attribute '{}'",
                                name
                            )));
                        }
                    },
                    Object::Generator(_) => match name.as_str() {
                        "__iter__" => NativeMethodKind::GeneratorIter,
                        "__next__" => NativeMethodKind::GeneratorNext,
                        "send" => NativeMethodKind::GeneratorSend,
                        "throw" => NativeMethodKind::GeneratorThrow,
                        "close" => NativeMethodKind::GeneratorClose,
                        _ => {
                            return Err(RuntimeError::new(format!(
                                "generator has no attribute '{}'",
                                name
                            )));
                        }
                    },
                    _ => return Err(RuntimeError::new("attribute access unsupported type")),
                };
                let native = self.heap.alloc_native_method(NativeMethodObject::new(kind));
                let bound = BoundMethod::new(native, generator);
                Ok(self.heap.alloc_bound_method(bound))
            }
            Value::Exception(exception) => match name.as_str() {
                "__cause__" => Ok(exception
                    .cause
                    .as_ref()
                    .map(|cause| Value::Exception((**cause).clone()))
                    .unwrap_or(Value::None)),
                "__context__" => Ok(exception
                    .context
                    .as_ref()
                    .map(|context| Value::Exception((**context).clone()))
                    .unwrap_or(Value::None)),
                "__suppress_context__" => Ok(Value::Bool(exception.suppress_context)),
                "exceptions" => {
                    let members = exception
                        .exceptions
                        .iter()
                        .cloned()
                        .map(Value::Exception)
                        .collect::<Vec<_>>();
                    Ok(self.heap.alloc_tuple(members))
                }
                _ => Err(RuntimeError::new(format!(
                    "exception has no attribute '{}'",
                    name
                ))),
            },
            _ => Err(RuntimeError::new("attribute access unsupported type")),
        };

        match looked_up {
            Ok(value) => Ok(value),
            Err(err) => {
                if let Some(default) = default {
                    if err.message.contains("has no attribute") {
                        Ok(default)
                    } else {
                        Err(err)
                    }
                } else {
                    Err(err)
                }
            }
        }
    }

    fn builtin_setattr(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(
                "setattr() got an unexpected keyword argument",
            ));
        }
        if args.len() != 3 {
            return Err(RuntimeError::new("setattr() expects three arguments"));
        }

        let target = args.remove(0);
        let name = match args.remove(0) {
            Value::Str(name) => name,
            _ => return Err(RuntimeError::new("attribute name must be string")),
        };
        let value = args.remove(0);

        match target {
            Value::Module(module) => {
                if let Object::Module(module_data) = &mut *module.kind_mut() {
                    module_data.globals.insert(name, value);
                }
            }
            Value::Instance(instance) => match self.store_attr_instance(&instance, &name, value)? {
                AttrMutationOutcome::Done => {}
                AttrMutationOutcome::ExceptionHandled => return Ok(Value::None),
            },
            Value::Class(class) => {
                if let Object::Class(class_data) = &mut *class.kind_mut() {
                    class_data.attrs.insert(name, value);
                }
            }
            Value::Function(func) => self.store_attr_function(&func, name, value)?,
            _ => return Err(RuntimeError::new("attribute assignment unsupported type")),
        }

        Ok(Value::None)
    }

    fn builtin_delattr(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(
                "delattr() got an unexpected keyword argument",
            ));
        }
        if args.len() != 2 {
            return Err(RuntimeError::new("delattr() expects two arguments"));
        }

        let target = args.remove(0);
        let name = match args.remove(0) {
            Value::Str(name) => name,
            _ => return Err(RuntimeError::new("attribute name must be string")),
        };

        match target {
            Value::Module(module) => {
                if let Object::Module(module_data) = &mut *module.kind_mut() {
                    if module_data.globals.remove(&name).is_none() {
                        return Err(RuntimeError::new(format!(
                            "module attribute '{}' does not exist",
                            name
                        )));
                    }
                }
            }
            Value::Class(class) => {
                if let Object::Class(class_data) = &mut *class.kind_mut() {
                    if class_data.attrs.remove(&name).is_none() {
                        return Err(RuntimeError::new(format!(
                            "class attribute '{}' does not exist",
                            name
                        )));
                    }
                }
            }
            Value::Instance(instance) => match self.delete_attr_instance(&instance, &name)? {
                AttrMutationOutcome::Done => {}
                AttrMutationOutcome::ExceptionHandled => return Ok(Value::None),
            },
            Value::Function(func) => self.delete_attr_function(&func, &name)?,
            _ => return Err(RuntimeError::new("attribute deletion unsupported type")),
        }

        Ok(Value::None)
    }

    fn builtin_hasattr(
        &mut self,
        args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if args.len() != 2 {
            return Err(RuntimeError::new("hasattr() expects two arguments"));
        }
        match self.builtin_getattr(args, kwargs) {
            Ok(_) => Ok(Value::Bool(true)),
            Err(err) if err.message.contains("has no attribute") => Ok(Value::Bool(false)),
            Err(err) => Err(err),
        }
    }

    fn builtin_super(
        &mut self,
        mut args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(
                "super() got an unexpected keyword argument",
            ));
        }
        if args.len() != 2 {
            return Err(RuntimeError::new(
                "super() currently requires explicit type and object arguments",
            ));
        }

        let start_class = match args.remove(0) {
            Value::Class(class) => class,
            _ => return Err(RuntimeError::new("super() first argument must be a class")),
        };
        let object_value = args.remove(0);
        let object_ref = self.receiver_from_value(&object_value)?;
        let object_type = self.class_of_value(&object_value).ok_or_else(|| {
            RuntimeError::new("super() second argument must be an instance or subclass")
        })?;

        let mro = self.class_mro_entries(&object_type);
        if !mro.iter().any(|entry| entry.id() == start_class.id()) {
            return Err(RuntimeError::new(
                "super(type, obj): obj must be an instance or subtype of type",
            ));
        }

        Ok(self
            .heap
            .alloc_super(SuperObject::new(start_class, object_ref, object_type)))
    }

    fn builtin_import(
        &mut self,
        mut args: Vec<Value>,
        mut kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if args.len() > 5 {
            return Err(RuntimeError::new("__import__() takes at most 5 arguments"));
        }

        let kw_name = kwargs.remove("name");
        let kw_globals = kwargs.remove("globals");
        let kw_locals = kwargs.remove("locals");
        let kw_fromlist = kwargs.remove("fromlist");
        let kw_level = kwargs.remove("level");
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(
                "__import__() got an unexpected keyword argument",
            ));
        }

        let name_value = if let Some(value) = kw_name {
            if !args.is_empty() {
                return Err(RuntimeError::new(
                    "__import__() got multiple values for argument 'name'",
                ));
            }
            value
        } else if !args.is_empty() {
            args.remove(0)
        } else {
            return Err(RuntimeError::new(
                "__import__() missing required argument 'name'",
            ));
        };
        let name = match name_value {
            Value::Str(name) => name,
            _ => return Err(RuntimeError::new("__import__() name must be string")),
        };

        if kw_globals.is_some() && !args.is_empty() {
            return Err(RuntimeError::new(
                "__import__() got multiple values for argument 'globals'",
            ));
        }
        if kw_locals.is_some() && args.len() > 1 {
            return Err(RuntimeError::new(
                "__import__() got multiple values for argument 'locals'",
            ));
        }
        let fromlist = if let Some(value) = kw_fromlist {
            if args.len() > 2 {
                return Err(RuntimeError::new(
                    "__import__() got multiple values for argument 'fromlist'",
                ));
            }
            value
        } else if args.len() > 2 {
            args[2].clone()
        } else {
            Value::None
        };
        let level = if let Some(value) = kw_level {
            if args.len() > 3 {
                return Err(RuntimeError::new(
                    "__import__() got multiple values for argument 'level'",
                ));
            }
            value_to_int(value)?
        } else if args.len() > 3 {
            value_to_int(args[3].clone())?
        } else {
            0
        };
        if level < 0 {
            return Err(RuntimeError::new("level must be >= 0"));
        }

        let resolved_name = self.resolve_import_name(&name, level as usize)?;
        let module = self.import_module_object(&resolved_name)?;
        let result = if self.fromlist_requested(&fromlist) {
            module
        } else {
            self.module_for_plain_import(&resolved_name, module)
        };
        Ok(Value::Module(result))
    }

    fn builtin_import_module(
        &mut self,
        mut args: Vec<Value>,
        mut kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if args.len() > 2 {
            return Err(RuntimeError::new(
                "import_module() takes at most 2 arguments",
            ));
        }
        let kw_name = kwargs.remove("name");
        let kw_package = kwargs.remove("package");
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(
                "import_module() got an unexpected keyword argument",
            ));
        }

        let name_value = if let Some(value) = kw_name {
            if !args.is_empty() {
                return Err(RuntimeError::new(
                    "import_module() got multiple values for argument 'name'",
                ));
            }
            value
        } else if !args.is_empty() {
            args.remove(0)
        } else {
            return Err(RuntimeError::new(
                "import_module() missing required argument 'name'",
            ));
        };
        let name = match name_value {
            Value::Str(name) => name,
            _ => return Err(RuntimeError::new("import_module() name must be string")),
        };

        let package_value = if let Some(value) = kw_package {
            if !args.is_empty() {
                return Err(RuntimeError::new(
                    "import_module() got multiple values for argument 'package'",
                ));
            }
            value
        } else if !args.is_empty() {
            args.remove(0)
        } else {
            Value::None
        };
        let package = match package_value {
            Value::None => None,
            Value::Str(package) => Some(package),
            _ => {
                return Err(RuntimeError::new(
                    "import_module() package must be string or None",
                ));
            }
        };

        let (level, requested) = split_relative_import_name(&name);
        let resolved_name = if level == 0 {
            name
        } else {
            let package = package.ok_or_else(|| {
                RuntimeError::new("import_module() relative import requires package argument")
            })?;
            self.resolve_import_name_from_package(&package, &requested, level)?
        };
        let module = self.import_module_object(&resolved_name)?;
        Ok(Value::Module(module))
    }

    fn builtin_find_spec(
        &mut self,
        mut args: Vec<Value>,
        mut kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if args.len() > 2 {
            return Err(RuntimeError::new("find_spec() takes at most 2 arguments"));
        }
        let kw_name = kwargs.remove("name");
        let kw_package = kwargs.remove("package");
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(
                "find_spec() got an unexpected keyword argument",
            ));
        }

        let name_value = if let Some(value) = kw_name {
            if !args.is_empty() {
                return Err(RuntimeError::new(
                    "find_spec() got multiple values for argument 'name'",
                ));
            }
            value
        } else if !args.is_empty() {
            args.remove(0)
        } else {
            return Err(RuntimeError::new(
                "find_spec() missing required argument 'name'",
            ));
        };
        let name = match name_value {
            Value::Str(name) => name,
            _ => return Err(RuntimeError::new("find_spec() name must be string")),
        };

        let package_value = if let Some(value) = kw_package {
            if !args.is_empty() {
                return Err(RuntimeError::new(
                    "find_spec() got multiple values for argument 'package'",
                ));
            }
            value
        } else if !args.is_empty() {
            args.remove(0)
        } else {
            Value::None
        };
        let package = match package_value {
            Value::None => None,
            Value::Str(package) => Some(package),
            _ => {
                return Err(RuntimeError::new(
                    "find_spec() package must be string or None",
                ));
            }
        };

        let (level, requested) = split_relative_import_name(&name);
        let resolved_name = if level == 0 {
            name
        } else {
            let package = package.ok_or_else(|| {
                RuntimeError::new("find_spec() relative import requires package argument")
            })?;
            self.resolve_import_name_from_package(&package, &requested, level)?
        };

        if let Some(existing) = self.modules.get(&resolved_name).cloned() {
            if let Object::Module(module_data) = &*existing.kind() {
                if let Some(spec) = module_data.globals.get("__spec__").cloned() {
                    return Ok(spec);
                }
            }
        }

        let Some(source_info) = self.find_module_source(&resolved_name) else {
            return Ok(Value::None);
        };
        let loader_name = if source_info.is_namespace {
            NAMESPACE_LOADER
        } else if source_info.is_bytecode {
            SOURCELESS_FILE_LOADER
        } else {
            SOURCE_FILE_LOADER
        };
        let origin = if source_info.is_namespace {
            None
        } else {
            Some(&source_info.path)
        };
        Ok(self.build_module_spec_value(
            &resolved_name,
            origin,
            Some(loader_name),
            source_info.is_package,
            source_info.package_dirs.as_slice(),
            source_info.is_namespace,
        ))
    }

    fn builtin_importlib_invalidate_caches(
        &mut self,
        args: Vec<Value>,
        kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if !args.is_empty() || !kwargs.is_empty() {
            return Err(RuntimeError::new("invalidate_caches() expects no arguments"));
        }
        let Some(sys_module) = self.modules.get("sys").cloned() else {
            return Ok(Value::None);
        };
        let Object::Module(module_data) = &mut *sys_module.kind_mut() else {
            return Ok(Value::None);
        };
        if let Some(Value::Dict(cache)) = module_data.globals.get("path_importer_cache").cloned() {
            if let Object::Dict(entries) = &mut *cache.kind_mut() {
                entries.clear();
            }
        }
        Ok(Value::None)
    }

    fn builtin_importlib_spec_from_file_location(
        &mut self,
        mut args: Vec<Value>,
        mut kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if args.len() < 2 || args.len() > 2 {
            return Err(RuntimeError::new(
                "spec_from_file_location() expects name and location",
            ));
        }
        let name = match args.remove(0) {
            Value::Str(value) => value,
            _ => return Err(RuntimeError::new("name must be string")),
        };
        let location = match args.remove(0) {
            Value::Str(value) => value,
            _ => return Err(RuntimeError::new("location must be string")),
        };
        let loader = kwargs
            .remove("loader")
            .unwrap_or(Value::Str(SOURCE_FILE_LOADER.to_string()));
        let search_locations = kwargs.remove("submodule_search_locations");
        kwargs.remove("target");
        if !kwargs.is_empty() {
            return Err(RuntimeError::new(
                "spec_from_file_location() got an unexpected keyword argument",
            ));
        }

        let mut entries = vec![
            (Value::Str("name".to_string()), Value::Str(name)),
            (Value::Str("loader".to_string()), loader),
            (Value::Str("origin".to_string()), Value::Str(location.clone())),
            (
                Value::Str("cached".to_string()),
                Value::Str(cache_path_from_source_path(&location)),
            ),
            (Value::Str("has_location".to_string()), Value::Bool(true)),
            (Value::Str("__spec__".to_string()), Value::None),
            (
                Value::Str("submodule_search_locations".to_string()),
                Value::None,
            ),
        ];
        if let Some(value) = search_locations {
            let normalized = if matches!(value, Value::None) {
                Value::None
            } else {
                let locations = self.collect_iterable_values(value)?;
                self.heap.alloc_list(locations)
            };
            if let Some((_, field)) = entries
                .iter_mut()
                .find(|(key, _)| matches!(key, Value::Str(name) if name == "submodule_search_locations"))
            {
                *field = normalized;
            }
        }
        Ok(self.heap.alloc_dict(entries))
    }

    fn builtin_frozen_importlib_spec_from_loader(
        &mut self,
        mut args: Vec<Value>,
        mut kwargs: HashMap<String, Value>,
    ) -> Result<Value, RuntimeError> {
        if args.is_empty() || args.len() > 4 {
            return Err(RuntimeError::new(
                "spec_from_loader() expects name, loader, and optional origin/is_package",
            ));
        }
        let name = match args.remove(0) {
            Value::Str(name) => name,
            _ => return Err(RuntimeError::new("spec_from_loader() name must be string")),
        };
        let loader = if !args.is_empty() {
            args.remove(0)
        } else {
            kwargs.remove("loader").unwrap_or(Value::None)
        };
        let origin = if !args.is_empty() {
            args.remove(0)
        } else {
            kwargs.remove("origin").unwrap_or(Value::None)
        };
        let is_package_value = if !args.is_empty() {
            args.remove(0)
        } else {
            kwargs.remove("is_package").unwrap_or(Value::Bool(false))
        };
        kwargs.remove("cached");
        kwargs.remove("submodule_search_locations");
        if !kwargs.is_empty() || !args.is_empty() {
            return Err(RuntimeError::new(
                "spec_from_loader() got an unexpected keyword argument",
            ));
        }
        let is_package = match is_package_value {
            Value::Bool(value) => value,
            other => is_truthy(&other),
        };
        let mut spec = self.build_module_spec_value(
            &name,
            None,
            if matches!(loader, Value::None) {
                None
            } else {
                Some(BUILTIN_MODULE_LOADER)
            },
            is_package,
            &[],
            false,
        );
        if let Value::Dict(spec_obj) = &mut spec {
            dict_set_value(spec_obj, Value::Str("loader".to_string()), loader);
            dict_set_value(spec_obj, Value::Str("origin".to_string()), origin.clone());
            dict_set_value(
                spec_obj,
                Value::Str("has_location".to_string()),
                Value::Bool(!matches!(origin, Value::None)),
            );
        }
        Ok(spec)
    }

