    fn opcode_info_by_number(&self, opcode: i64) -> Option<&crate::bytecode::metadata::OpcodeInfo> {
        if opcode < 0 || opcode > i64::from(u16::MAX) {
            return None;
        }
        let code = opcode as u16;
        self.opcode_metadata()
            .opcodes
            .iter()
            .find(|info| info.code == code)
    }

